```python
import os
import pickle

class IndexCache:
    def __init__(self, index_file_path):
        self.index_file_path = index_file_path
        self.cache_path = os.path.join(os.path.dirname(index_file_path), f'{os.path.basename(index_file_path)}.cache')

    def get(self):
        if os.path.exists(self.cache_path):
            with open(self.cache_path, 'rb') as f:
                return pickle.load(f)
        else:
            return None

    def set(self, value):
        with open(self.cache_path, 'wb') as f:
            pickle.dump(value, f)

    def delete(self):
        if os.path.exists(self.cache_path):
            os.remove(self.cache_path)
```

